#### 2. **No Authentication/Authorization (OWASP A01:2021 - Broken Access Control)**
**Severity:** CRITICAL

**Issue:** Both endpoints are completely unauthenticated. Any user can access sensitive data (/users endpoint) without any credentials.

**Recommendation:**
```javascript
const jwt = require('jsonwebtoken');

// Middleware to verify JWT tokens
function authenticateToken(req, res, next) {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) {
    return res.status(401).json({ error: 'Access token required' });
  }

  jwt.verify(token, process.env.JWT_SECRET, (err, user) => {
    if (err) {
      return res.status(403).json({ error: 'Invalid or expired token' });
    }
    req.user = user;
    next();
  });
}

// Apply authentication to sensitive endpoints
app.get('/users', authenticateToken, (req, res) => {
  // Only authenticated users can access this
  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});

// Health check can remain public (optional)
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});
```

