1	#!/usr/bin/env node
2	/**
3	 * AI Sandbox HTTP wrapper for the Test 7 batch runner.
4	 *
5	 * Listens on port 3000 (ALB requirement) and satisfies the health check at
6	 * GET / while providing a simple API to trigger and monitor batch runs.
7	 *
8	 * Routes:
9	 *   GET  /        — HTML status page; always returns 200 (ALB health check)
10	 *   GET  /status  — JSON run state
11	 *   GET  /logs    — plain-text log tail  (?n=N lines, default 100)
12	 *   POST /run     — start a run; body is JSON with optional overrides:
13	 *                     { models, scenarios, defences, reps,
14	 *                       s3Bucket, s3Prefix, s3Region, awsRegion, runId }
15	 *                   Returns 202 if accepted, 409 if a run is already in progress.
16	 */
17	
18	import http from "http";
19	import { spawn } from "child_process";
20	import { readFileSync } from "fs";
21	
22	const PORT = 3000;
23	const MAX_LOG_LINES = 20000;
24	const ENTRYPOINTS = {
25	  "1": "/docker-entrypoint-test1.sh",
26	  "3": "/docker-entrypoint-test3.sh",
27	  "3a": "/docker-entrypoint-test3a.sh",
28	  "4": "/docker-entrypoint-test4.sh",
29	  "7": "/docker-entrypoint.sh",
30	  "8": "/docker-entrypoint-test8.sh",
31	  "9": "/docker-entrypoint-test9.sh",
32	  "9a": "/docker-entrypoint-test9a.sh",
33	  "8b6": "/docker-entrypoint-test8b6.sh",
34	  "10": "/docker-entrypoint-test10.sh",
35	  "12": "/docker-entrypoint-test12.sh",
36	  "12a": "/docker-entrypoint-test12a.sh",
37	  "12b": "/docker-entrypoint-test12b.sh",
38	  "12c": "/docker-entrypoint-test12c.sh",
39	  "13": "/docker-entrypoint-test13.sh",
40	  "14": "/docker-entrypoint-test14.sh",
41	  "15": "/docker-entrypoint-test15.sh",
42	  "16": "/docker-entrypoint-test16.sh",
43	  "17": "/docker-entrypoint-test17.sh",
44	  "18": "/docker-entrypoint-test18.sh",
45	};
46	const DEFAULT_TEST = process.env.TEST_NUM || "7";
47	const BUILD_VERSION = JSON.parse(readFileSync(new URL("./package.json", import.meta.url), "utf8")).version;
48	
49	// ---------------------------------------------------------------------------
50	// Run state
51	// ---------------------------------------------------------------------------
52	
53	const INITIAL_PROGRESS = {
54	  totalCombinations: 0,
55	  completedCombinations: 0,
56	  failedCombinations: 0,
57	  completedRuns: 0,       // individual repetitions
58	  lastGES: null,
59	};
60	
61	let state = {
62	  status: "idle",   // idle | running | done | failed
63	  runId: null,
64	  params: null,
65	  startedAt: null,
66	  finishedAt: null,
67	  exitCode: null,
68	  pid: null,
69	  logLines: [],
70	  progress: { ...INITIAL_PROGRESS },
71	};
72	
73	let currentProcess = null;
74	
75	function appendLog(line) {
76	  state.logLines.push(line);
77	  if (state.logLines.length > MAX_LOG_LINES) state.logLines.shift();
78	  process.stdout.write(line + "\n");
79	
80	  // Track progress from log output
81	  // Total combinations: "[1/12]" pattern from entrypoint or ">>> N combinations queued"
82	  const totalMatch = line.match(/\[\d+\/(\d+)\]/);
83	  if (totalMatch) state.progress.totalCombinations = parseInt(totalMatch[1], 10);
84	  const queuedMatch = line.match(/>>> (\d+) combinations queued/);
85	  if (queuedMatch) state.progress.totalCombinations = parseInt(queuedMatch[1], 10);
86	
87	  // Combination completed (Test 7: "Completed in", Test 3: "DONE in")
88	  if (/Completed in \d+s/.test(line) || /\] DONE in \d+s/.test(line)) {
89	    state.progress.completedCombinations++;
90	  }
91	  // Combination failed
92	  if (/WARNING: run failed/.test(line) || /\] FAILED:/.test(line)) {
93	    state.progress.completedCombinations++;
94	    state.progress.failedCombinations++;
95	  }
96	
97	  // Individual test result (one per repetition)
98	  if (/^RESULT:/.test(line) || /^\s+RESULT:/.test(line)) {
99	    state.progress.completedRuns++;
100	  }
101	  // Extract GES from result blocks
102	  const gesMatch = line.match(/GES:\s+([\d.]+)/);
103	  if (gesMatch) state.progress.lastGES = parseFloat(gesMatch[1]);
104	}
105	
106	function startRun(params) {
107	  const env = Object.assign({}, process.env);
108	  const testNum = String(params.test || DEFAULT_TEST);
109	  const entrypoint = ENTRYPOINTS[testNum];
110	  if (!entrypoint) {
111	    throw new Error(`Unknown test number: ${testNum}. Valid: ${Object.keys(ENTRYPOINTS).join(", ")}`);
112	  }
113	
114	  // Test 7 env vars
115	  if (params.models)    env.TEST7_MODELS    = String(params.models);
116	  if (params.scenarios) env.TEST7_SCENARIOS = String(params.scenarios);
117	  if (params.defences)  env.TEST7_DEFENCES  = String(params.defences);
118	  if (params.reps)      env.TEST7_REPS      = String(params.reps);
119	  if (params.effort)    env.TEST7_EFFORT    = String(params.effort);
120	  if (params.runId)     env.TEST7_RUN_ID    = String(params.runId);
121	
122	  // Test 3 env vars
123	  if (params.models)    env.TEST3_MODELS    = String(params.models);
124	  if (params.scenarios) env.TEST3_SCENARIOS = String(params.scenarios);
125	  if (params.defences)  env.TEST3_DEFENCES  = String(params.defences);
126	  if (params.parallel)  env.PARALLEL_JOBS   = String(params.parallel);
127	  if (params.runId)     env.TEST3_RUN_ID    = String(params.runId);
128	
129	  // Test 1 env vars
130	  if (params.effort)    env.TEST1_EFFORT    = String(params.effort);
131	  if (params.config)    env.TEST1_CONFIG    = String(params.config);
132	
133	  // Test 3a env vars
134	  if (params.efforts)   env.TEST3A_EFFORTS  = String(params.efforts);
135	  if (params.reps)      env.TEST3A_REPS     = String(params.reps);
136	  if (params.runId)     env.TEST3A_RUN_ID   = String(params.runId);
137	
138	  // Test 9a env vars
139	  if (params.matrix)    env.TEST9A_MATRIX   = String(params.matrix);
140	  if (params.reps)      env.TEST9A_REPS     = String(params.reps);
141	  if (params.runId)     env.TEST9A_RUN_ID   = String(params.runId);
142	
143	  // Test 8 env vars
144	  if (params.effort)    env.TEST8_EFFORT    = String(params.effort);
145	  if (params.reps)      env.TEST8_REPS      = String(params.reps);
146	  if (params.models)    env.TEST8_MODELS    = String(params.models);
147	  if (params.hardened)  env.TEST8_HARDENED   = "true";
148	  if (params.prompt)    env.TEST8_PROMPT     = String(params.prompt);
149	  if (params.b6)        env.TEST8_B6         = "true";
150	
151	  // Test 8 B6 env vars
152	  if (params.effort)    env.TEST8B6_EFFORT  = String(params.effort);
153	  if (params.reps)      env.TEST8B6_REPS    = String(params.reps);
154	  if (params.models)    env.TEST8B6_MODELS  = String(params.models);
155	
156	  // Test 10/11 env vars
157	  if (params.defences)      env.TEST10_DEFENCES     = String(params.defences);
158	  if (params.model)         env.TEST10_MODEL        = String(params.model);
159	  if (params.effort)        env.TEST10_EFFORT       = String(params.effort);
160	  if (params.judgeEffort)   env.TEST10_JUDGE_EFFORT = String(params.judgeEffort);
161	  if (params.reps)          env.TEST10_REPS         = String(params.reps);
162	
163	  // Test 15 env vars (FPR under prompt v2)
164	  if (params.prompt)    env.TEST15_PROMPT   = String(params.prompt);
165	  if (params.task)      env.TEST15_TASK     = String(params.task);
166	  if (params.reps)      env.TEST15_REPS     = String(params.reps);
167	  if (params.model)     env.TEST15_MODEL    = String(params.model);
168	
169	  // Generic env passthrough (test 12 / AgentDojo uses this)
170	  if (params.env && typeof params.env === "object") {
171	    for (const [k, v] of Object.entries(params.env)) {
172	      env[k] = String(v);
173	    }
174	  }
175	
176	  // Shared env vars
177	  if (params.s3Bucket)  env.S3_BUCKET       = String(params.s3Bucket);
178	  if (params.s3Prefix)  env.S3_PREFIX       = String(params.s3Prefix);
179	  if (params.s3Region)  env.S3_REGION       = String(params.s3Region);
180	  if (params.awsRegion) env.AWS_REGION      = String(params.awsRegion);
181	  if (params.bedrockRegion) env.BEDROCK_REGION = String(params.bedrockRegion);
182	
183	  const runId = env.TEST7_RUN_ID || env.TEST3_RUN_ID || new Date().toISOString().replace(/[:.]/g, "");
184	
185	  state = {
186	    status: "running",
187	    runId,
188	    params,
189	    startedAt: new Date().toISOString(),
190	    finishedAt: null,
191	    exitCode: null,
192	    pid: null,
193	    logLines: [],
194	    progress: { ...INITIAL_PROGRESS },
195	  };
196	
197	  const child = spawn(entrypoint, [], {
198	    env,
199	    stdio: ["ignore", "pipe", "pipe"],
200	  });
201	
202	  state.pid = child.pid;
203	  currentProcess = child;
204	
205	  child.stdout.on("data", (data) => {
206	    data.toString().split("\n").filter(Boolean).forEach(appendLog);
207	  });
208	
209	  child.stderr.on("data", (data) => {
210	    data.toString().split("\n").filter(Boolean).forEach((l) => appendLog("[ERR] " + l));
211	  });
212	
213	  child.on("close", (code) => {
214	    state.status = code === 0 ? "done" : "failed";
215	    state.exitCode = code;
216	    state.finishedAt = new Date().toISOString();
217	    currentProcess = null;
218	    console.log(`Run ${runId} finished — exit code ${code}`);
219	  });
220	
221	  child.on("error", (err) => {
222	    state.status = "failed";
223	    state.exitCode = -1;
224	    state.finishedAt = new Date().toISOString();
225	    currentProcess = null;
226	    appendLog("[ERROR] Failed to spawn entrypoint: " + err.message);
227	  });
228	}
229	
230	// ---------------------------------------------------------------------------
231	// HTTP server
232	// ---------------------------------------------------------------------------
233	
234	const server = http.createServer((req, res) => {
235	  const url = new URL(req.url, "http://localhost:" + PORT);
236	
237	  // ── GET / — health check + status page ───────────────────────────────────
238	  if (req.method === "GET" && url.pathname === "/") {
239	    const colour = { idle: "#888", running: "#4af", done: "#4f4", failed: "#f44" }[state.status] || "#888";
240	    const logHtml = state.logLines.slice(-100)
241	      .map((l) => l.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;"))
242	      .join("\n");
243	
244	    res.writeHead(200, { "Content-Type": "text/html; charset=utf-8", "Cache-Control": "no-store" });
245	    res.end(`<!DOCTYPE html>
246	<html lang="en">
247	<head>
248	  <meta charset="utf-8">
249	  <title>Judge AI Dredd — Test Runner</title>
250	  <link rel="icon" href="/favicon.ico" type="image/x-icon">
251	  <style>
252	    body { font-family: monospace; background: #111; color: #ccc; padding: 2em; margin: 0; }
253	    h1   { color: #fff; margin-top: 0; }
254	    h2   { color: #aaa; }
255	    .badge { display: inline-block; padding: .2em .8em; border-radius: 3px;
256	             background: ${colour}; color: #fff; font-weight: bold; }
257	    code { background: #1a1a1a; padding: .1em .4em; border-radius: 2px; }
258	    pre  { background: #1a1a1a; padding: 1em; border-radius: 4px;
259	           overflow: auto; max-height: 60vh; white-space: pre-wrap; word-break: break-all; }
260	    table { border-collapse: collapse; margin-top: .5em; }
261	    td, th { padding: .2em 1em .2em 0; text-align: left; }
262	  </style>
263	</head>
264	<body>
265	  <h1>Judge AI Dredd — Test Runner</h1>
266	  <p style="color:#666;margin-top:-.5em">v${BUILD_VERSION}</p>
267	  <table>
268	    <tr><th>Status</th>   <td><span class="badge">${state.status}</span></td></tr>
269	    ${state.runId      ? `<tr><th>Run ID</th>    <td><code>${state.runId}</code></td></tr>` : ""}
270	    ${state.startedAt  ? `<tr><th>Started</th>   <td><code>${state.startedAt}</code></td></tr>` : ""}
271	    ${state.finishedAt ? `<tr><th>Finished</th>  <td><code>${state.finishedAt}</code> (exit ${state.exitCode})</td></tr>` : ""}
272	    ${state.pid        ? `<tr><th>PID</th>       <td><code>${state.pid}</code></td></tr>` : ""}
273	    ${state.progress.totalCombinations > 0
274	      ? `<tr><th>Progress</th>  <td><strong>${state.progress.completedCombinations} / ${state.progress.totalCombinations}</strong> combinations${state.progress.failedCombinations ? ` (${state.progress.failedCombinations} failed)` : ""} &mdash; ${state.progress.completedRuns} runs completed${state.progress.lastGES !== null ? `, last GES: ${state.progress.lastGES}` : ""}</td></tr>`
275	      : ""}
276	  </table>
277	  ${state.status === "idle"
278	    ? "<p>No run in progress. <code>POST /run</code> with a JSON body to start one.</p>"
279	    : ""}
280	  <h2>Log (last 100 of ${state.logLines.length} lines)</h2>
281	  <pre>${logHtml || "(empty)"}</pre>
282	</body>
283	</html>`);
284	    return;
285	  }
286	
287	  // ── GET /favicon.ico ──────────────────────────────────────────────────────
288	  if (req.method === "GET" && url.pathname === "/favicon.ico") {
289	    try {
290	      const ico = readFileSync("/app/src/web/favicon.ico");
291	      res.writeHead(200, { "Content-Type": "image/x-icon", "Cache-Control": "public, max-age=86400" });
292	      res.end(ico);
293	    } catch {
294	      res.writeHead(404);
295	      res.end();
296	    }
297	    return;
298	  }
299	
300	  // ── GET /status — JSON state ──────────────────────────────────────────────
301	  if (req.method === "GET" && url.pathname === "/status") {
302	    res.writeHead(200, { "Content-Type": "application/json", "Cache-Control": "no-store" });
303	    res.end(JSON.stringify({
304	      version:     BUILD_VERSION,
305	      status:      state.status,
306	      runId:       state.runId,
307	      params:      state.params,
308	      startedAt:   state.startedAt,
309	      finishedAt:  state.finishedAt,
310	      exitCode:    state.exitCode,
311	      pid:         state.pid,
312	      bufferedLogLines: state.logLines.length,
313	      progress:    state.progress,
314	    }));
315	    return;
316	  }
317	
318	  // ── GET /logs — plain-text log tail ──────────────────────────────────────
319	  if (req.method === "GET" && url.pathname === "/logs") {
320	    const n = Math.min(parseInt(url.searchParams.get("n") || "100", 10), MAX_LOG_LINES);
321	    res.writeHead(200, { "Content-Type": "text/plain; charset=utf-8", "Cache-Control": "no-store" });
322	    res.end(state.logLines.slice(-n).join("\n"));
323	    return;
324	  }
325	
326	  // ── POST /run — start a run ───────────────────────────────────────────────
327	  if (req.method === "POST" && url.pathname === "/run") {
328	    if (state.status === "running") {
329	      res.writeHead(409, { "Content-Type": "application/json" });
330	      res.end(JSON.stringify({ error: "A run is already in progress", runId: state.runId }));
331	      return;
332	    }
333	
334	    let body = "";
335	    req.on("data", (chunk) => (body += chunk));
336	    req.on("end", () => {
337	      let params = {};
338	      try {
339	        if (body.trim()) params = JSON.parse(body);
340	      } catch {
341	        res.writeHead(400, { "Content-Type": "application/json" });
342	        res.end(JSON.stringify({ error: "Invalid JSON body" }));
343	        return;
344	      }
345	
346	      startRun(params);
347	      res.writeHead(202, { "Content-Type": "application/json" });
348	      res.end(JSON.stringify({ message: "Run started", runId: state.runId, status: "running" }));
349	    });
350	    return;
351	  }
352	
353	  // ── POST /stop — kill the running process ──────────────────────────────────
354	  if (req.method === "POST" && url.pathname === "/stop") {
355	    if (state.status !== "running" || !currentProcess) {
356	      res.writeHead(409, { "Content-Type": "application/json" });
357	      res.end(JSON.stringify({ error: "No run in progress" }));
358	      return;
359	    }
360	    const pid = currentProcess.pid;
361	    appendLog(`[STOP] Killing process ${pid} via POST /stop`);
362	    currentProcess.kill("SIGTERM");
363	    setTimeout(() => {
364	      if (currentProcess) currentProcess.kill("SIGKILL");
365	    }, 5000);
366	    res.writeHead(200, { "Content-Type": "application/json" });
367	    res.end(JSON.stringify({ message: "Stop signal sent", pid }));
368	    return;
369	  }
370	
371	  res.writeHead(404, { "Content-Type": "application/json" });
372	  res.end(JSON.stringify({ error: "Not found", path: url.pathname }));
373	});
374	
375	server.listen(PORT, "0.0.0.0", () => {
376	  console.log(`Judge AI Dredd v${BUILD_VERSION} listening on 0.0.0.0:${PORT} (default test: ${DEFAULT_TEST})`);
377	  console.log("  GET  /        health check + status page");
378	  console.log("  GET  /status  JSON run state");
379	  console.log("  GET  /logs    plain-text log tail (?n=N)");
380	  console.log("  POST /run     start a run (JSON body with optional overrides)");
381	  console.log("  POST /stop    kill the running process");
382	});
383	
384	// ---------------------------------------------------------------------------
385	// Graceful shutdown
386	// ---------------------------------------------------------------------------
387	
388	process.on("SIGTERM", () => {
389	  console.log("SIGTERM received — draining connections");
390	  server.close(() => {
391	    if (currentProcess) {
392	      console.log("Forwarding SIGTERM to runner process (pid " + currentProcess.pid + ")");
393	      currentProcess.kill("SIGTERM");
394	    }
395	    process.exit(0);
396	  });
397	});
